                /**
                 * Format: date-time
                 * @description Timestamp when the payment was last updated
                 */
                updatedAt: string;
                /** @description Unique blockchain identifier for the payment */
                blockchainIdentifier: string;
                /** @description Identifier of the agent that is being paid */
                agentIdentifier: string | null;
                /**
                 * @description Pricing type of the agent (Fixed, Free, or Dynamic)
                 * @enum {string}
                 */
                pricingType: "Fixed" | "Free" | "Dynamic";
                /**
                 * Format: date-time
                 * @description Timestamp when the payment was last checked on-chain. Null if never checked
                 */
                lastCheckedAt: string | null;
                /** @description Unix timestamp (in milliseconds) by which the buyer must submit the payment transaction. Null if not set */
                payByTime: string | null;
                /** @description Unix timestamp (in milliseconds) by which the seller must submit the result */
                submitResultTime: string;
                /** @description Unix timestamp (in milliseconds) after which funds can be unlocked if no disputes */
                unlockTime: string;
                /** @description Amount of collateral to return in lovelace. Null if no collateral */
                collateralReturnLovelace: string | null;
                /** @description Unix timestamp (in milliseconds) after which external dispute resolution can occur */
                externalDisputeUnlockTime: string;
